#include<bits/stdc++.h>
using namespace std;
int v[110];
int dp[110][31][31][31];
const int mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long C[110][110];
int main()
{
    for(int i=0;i<=101;i++)
    {
        C[i][0]=1;
        for(int j=1;j<=i;j++)
        {
            C[i][j]=(C[i-1][j]+C[i-1][j-1])%mod;
        }
    }
	int n,m,k;
	scanf("%d%d%d",&n,&m,&k);
	int K=k;
	for(int i=0;i<=m;i++)
	{
		scanf("%d",&v[i]);
	} 
	dp[0][0][0][0]=1;
	for(int i=0;i<=m;i++)
	{
		for(int j=0;j<=n;j++)
		{
			for(int k=0;k<=K;k++)
			{
				for(int p=0;p<=n/2;p++)
                {
                    for(int t=0;t<=n-j;t++)
                    {
                        dp[i+1][j+t][k+(t+p)%2][(t+p)/2]+=dp[i][j][k][p]*fastpow(v[i],t)%mod*C[n-j][t]%mod;
                        dp[i+1][j+t][k+(t+p)%2][(t+p)/2]%=mod;
                    }
                }
			}
		}
	}
    long long ans=0;
    for(int k=0;k<=K;k++)
    {
        for(int p=0;p<=n/2;p++)
        {
            if(k+__builtin_popcount(p)<=K)
            {
                ans=(ans+dp[m+1][n][k][p])%mod;
            }
        }
    }
    printf("%lld",ans);
	return 0;
}
